mapper.select:
SELECT
FROM PLACE p JOIN REGION r ON p.region_id = r.region_id
WHERE p.place_id = #{placeId}

SELECT COUNT(*)
FROM PLACE_NEARBY_FACILITY_CACHE
WHERE place_id = #{placeId}
  AND facility_type = #{facilityType}
  AND search_radius_m = #{searchRadiusM}
  AND fetched_at >= #{validAfter}

SELECT facility_id
FROM FACILITY
WHERE source_provider = #{sourceProvider}
  AND external_id = #{externalId}

